    enabled: publishArtifacts,
    artifactBranch,
    preserveExisting: preserveExistingArtifacts,
    repoFullName,
    prNumber,
    head,
    base,
    ledgerRef,
    reviewId,
    generatedAt,
    commits,
    sessions,
  });
  const report = renderReport({
    marker,
    mode,
    ledgerRef,
    repoFullName,
    prNumber,
    generatedAt,
    base,
    head,
    commits,
    sessions,
    changedFiles,
    testFiles,
    qaDigest,
    missingLedgerRef: !refExists,
    artifact,
  });
  console.log(report);
}

